}


function getDifferenceInDays(dt1, dt2){
	// STRY0071533 -  https://www.servicenowguru.com/scripting/client-scripts-scripting/client-side-dates-in-servicenow/
	// based on the article referenced above, this should work for the function below.
	// we can use the user's date and time format instead of forcing one.

	var dateDiff = new Date();
	if (dt2 > dt1){
		return getDifferenceInDays(dt2, dt1);
	}else if (dt2 < dt1){
		dateDiff = Math.floor((dt1 - dt2) / (1000 * 60 * 60 * 24));    // get difference in days
	}
	return dateDiff;

